mapper.select:
SELECT ,
       p.material_name AS product_name
FROM silicone_coarse_uv_compatibility c
LEFT JOIN silicone_coarse_uv_product p ON c.product_id = p.id
WHERE c.product_id = #{productId}
  AND c.post_processing_step = #{postProcessingStep}

mapper.update:
UPDATE silicone_coarse_uv_compatibility SET
    product_id = #{productId},
    post_processing_step = #{postProcessingStep},
    compatibility_status = #{compatibilityStatus},
    display_order = #{displayOrder}
WHERE id = #{id}
